 1	import type { FC, ReactNode } from 'react';
 2	
 3	import { Card, CardBody, CardHeader, CardTitle, Split, SplitItem } from '@patternfly/react-core';
 4	
 5	type SelectableCardProps = {
 6	  /** The title of the card. It can be any element - a string, a React component, etc. */
 7	  title: ReactNode;
 8	  /** Optional: A logo or symbol to be displayed along with the title. It can be any element - a string, a React component, etc. */
 9	  titleLogo?: ReactNode;
10	  /** Optional: The content of the card. It can be any element - a string, a React component, etc. */
11	  content?: ReactNode;
12	  /** A function that will be called when the card is clicked. It receives a single argument, `isSelected`, which is a boolean indicating the selected state of the card. */
13	  onChange: (isSelected: boolean) => void;
14	  /** A boolean indicating whether the card is currently selected. */
15	  isSelected: boolean;
16	  /** Optional: A boolean indicating whether the card should be displayed in a compact form. This may affect things like the card's padding and margin. */
17	  isCompact?: boolean;
18	  /** Optional: A string representing a CSS class name. This class will be applied to the card's top-level DOM element, allowing you to style the card with custom CSS. */
19	  className?: string;
20	  /** Optional: A string to use for the `data-testid` attribute. */
21	  testId?: string;
22	};
23	
24	/**
25	 * SelectableCard component
26	 * @param props The properties of the SelectableCard
27	 */
28	export const SelectableCard: FC<SelectableCardProps> = ({
29	  className,
30	  content,
31	  isCompact,
32	  isSelected,
33	  onChange,
34	  testId,
35	  title,
36	  titleLogo,
37	}) => {
38	  // Handler function to toggle selection and call onChange
39	  const handleClick = () => {
40	    // Flip the isSelected status and send the new status via the onChange handler
41	    onChange(!isSelected);
42	  };
43	
44	  return (
45	    <Card
46	      data-testid={testId}
47	      className={`forklift-selectable-gallery-card ${className}`}
48	      id="selectable-card"
49	      onKeyDown={handleClick}
50	      onClick={handleClick}
51	      isSelectable
52	      isCompact={isCompact}
53	      isSelected={isSelected}
54	    >
55	      <CardHeader
56	        selectableActions={{
57	          name: 'selectable-card-header',
58	          onChange: handleClick,
59	          selectableActionAriaLabelledby: 'selectable-card-header',
60	          selectableActionId: 'selectable-card-header',
61	          variant: 'single',
62	        }}
63	      >
64	        {titleLogo ? (
65	          <CardTitle>
66	            <Split className="forklift--create-provider-edit-card-title">
67	              <SplitItem>{titleLogo}</SplitItem>
68	              <SplitItem isFilled>{title}</SplitItem>
69	            </Split>
70	          </CardTitle>
71	        ) : (
72	          <CardTitle>{title}</CardTitle>
73	        )}
74	      </CardHeader>
75	      {content && <CardBody>{content}</CardBody>}
76	    </Card>
77	  );
78	};

